import { db } from './src/server/db/client.ts'
import { nodes, edges, graphMetadata } from './src/server/db/schema.ts'
import { writeFileSync } from 'node:fs'

const nodeRows = db.select\(\).from\(nodes\).all\(\)
const edgeRows = db.select\(\).from\(edges\).all\(\)
const metaRows = db.select\(\).from\(graphMetadata\).limit\(1\).all\(\)
const meta = metaRows[0]

const graph = {
  nodes: nodeRows.map\(n => \({
    id: n.id, x: n.x, y: n.y, label: n.label, type: n.type,
    searchable: n.searchable, floor: n.floor,
    ...\(n.roomNumber != null && { roomNumber: n.roomNumber }\),
    ...\(n.description != null && { description: n.description }\),
    ...\(n.buildingName != null && { buildingName: n.buildingName }\),
    ...\(n.accessibilityNotes != null && { accessibilityNotes: n.accessibilityNotes }\),
  }\)\),
  edges: edgeRows.map\(e => \({
    id: e.id, sourceId: e.sourceId, targetId: e.targetId,
    standardWeight: e.standardWeight, accessibleWeight: e.accessibleWeight,
    accessible: e.accessible, bidirectional: e.bidirectional,
    ...\(e.accessibilityNotes != null && { accessibilityNotes: e.accessibilityNotes }\),
  }\)\),
  metadata: { buildingName: meta.buildingName, floor: meta.floor, lastUpdated: meta.lastUpdated }
}

writeFileSync\('./src/server/assets/campus-graph.json', JSON.stringify\(graph, null, 2\)\)
console.log\('Exported', nodeRows.length, 'nodes,', edgeRows.length, 'edges'\)
" 2>&1)
